        if (a.drainVar > 0) {
          d.fightMesFormat.color = 52224;
          a.hp += a.drainVar;
          a.mHP -= a.drainVar;
          a.hitMax();
          a.drainVar = 0;
        }
        if (d.fightMesY == 560) {
          d.fightMesY -= 25;
          for (var c = 0; c < 9;) {
            if (c != d.fightMesCurrent) {
              var b = d.fightMes[c];
              b.set_y(b.get_y() - 25);
            }
            ++c;
          }
        }
        d.fightMes[d.fightMesCurrent].setTextFormat(d.fightMesFormat);
        d.fightMes[d.fightMesCurrent].set_y(d.fightMesY);
        d.fightMesY += 25;
        d.fightMes[d.fightMesCurrent].set_visible(true);
        d.fightMesCurrent++;
